import { relations } from "drizzle-orm";
import { gatewayInstallations } from "./tables/gateway-installations";
import { gatewayLifecycleLogs } from "./tables/gateway-lifecycle-log";
import { gatewayTokens } from "./tables/gateway-tokens";
import { orgEntities } from "./tables/org-entities";
import { orgEntityEdges } from "./tables/org-entity-edges";
import { orgEventEntities } from "./tables/org-event-entities";
import { orgEvents } from "./tables/org-events";
import { orgIntegrations } from "./tables/org-integrations";

/**
 * Define relations between tables for Drizzle ORM queries
 *
 * Note: Organizations are managed by Clerk, not in our database.
 * Tables reference Clerk org IDs via clerkOrgId fields (no FK constraints).
 */

// Gateway relations
export const gatewayInstallationsRelations = relations(
  gatewayInstallations,
  ({ many }) => ({
    tokens: many(gatewayTokens),
    orgIntegrations: many(orgIntegrations),
    lifecycleLogs: many(gatewayLifecycleLogs),
  })
);

export const gatewayLifecycleLogsRelations = relations(
  gatewayLifecycleLogs,
  ({ one }) => ({
    installation: one(gatewayInstallations, {
      fields: [gatewayLifecycleLogs.installationId],
      references: [gatewayInstallations.id],
    }),
  })
);

export const gatewayTokensRelations = relations(gatewayTokens, ({ one }) => ({
  installation: one(gatewayInstallations, {
    fields: [gatewayTokens.installationId],
    references: [gatewayInstallations.id],
  }),
}));

export const orgIntegrationsRelations = relations(
  orgIntegrations,
  ({ one }) => ({
    installation: one(gatewayInstallations, {
      fields: [orgIntegrations.installationId],
      references: [gatewayInstallations.id],
    }),
  })
);

export const orgEventsRelations = relations(orgEvents, ({ many }) => ({
  entityEvents: many(orgEventEntities),
}));

// Entity-event junction relations
export const orgEventEntitiesRelations = relations(
  orgEventEntities,
  ({ one }) => ({
    entity: one(orgEntities, {
      fields: [orgEventEntities.entityId],
      references: [orgEntities.id],
    }),
    event: one(orgEvents, {
      fields: [orgEventEntities.eventId],
      references: [orgEvents.id],
    }),
  })
);

// Entity↔entity edges relations
export const orgEntityEdgesRelations = relations(orgEntityEdges, ({ one }) => ({
  sourceEntity: one(orgEntities, {
    fields: [orgEntityEdges.sourceEntityId],
    references: [orgEntities.id],
  }),
  targetEntity: one(orgEntities, {
    fields: [orgEntityEdges.targetEntityId],
    references: [orgEntities.id],
  }),
  sourceEvent: one(orgEvents, {
    fields: [orgEntityEdges.sourceEventId],
    references: [orgEvents.id],
  }),
}));

    if (
      prev.category !== filters.category ||
      prev.search !== filters.search
    ) {
      setLoadedEntities([]);
      setNextCursor(undefined);
      setLiveEntities([]);
      prevFiltersRef.current = {
        category: filters.category,
        search: filters.search,
      };
    }
  }, [filters.category, filters.search]);

  const effectiveHasMore =
    nextCursor !== undefined ? nextCursor !== null : data.hasMore;
  const effectiveCursor =
    nextCursor !== undefined ? nextCursor : data.nextCursor;

  // Live entities
  const [liveEntities, setLiveEntities] = useState<EntityNotification[]>([]);
  const { organization } = useOrganization();
  const isDefaultView =
    filters.search === "" && nextCursor === undefined;

  const { status } = useRealtime({
    channels: organization?.id ? [`org-${organization.id}`] : [],
    events: ["org.entity"],
    enabled: !!organization?.id && isDefaultView,
    onData({ data: notification }) {
      if (notification.clerkOrgId !== data.clerkOrgId) return;
      if (
        category &&
        notification.category !== category
      )
        return;
      setLiveEntities((prev) => [notification, ...prev]);
    },
  });

  // Stable set of DB entity externalIds
  const dbExternalIds = useMemo(
    () =>
      new Set([
        ...data.entities.map((e) => e.externalId),
        ...loadedEntities.map((e) => e.externalId),
      ]),
    [data.entities, loadedEntities]
  );

  // Merge: live prepend + initial page + loaded pages
  const allEntities = useMemo(() => {
    const newLive = liveEntities.filter(
      (e) => !dbExternalIds.has(e.entityExternalId)
    );
    const liveAsEntities: Entity[] = newLive.map((e) => ({
      id: 0, // Placeholder — not used for keying
      externalId: e.entityExternalId,
      category: e.category,
      key: e.key,
      value: e.value,
      state: e.state,
      url: e.url,
      confidence: null,
      occurrenceCount: e.occurrenceCount,
      lastSeenAt: e.lastSeenAt,
      createdAt: e.lastSeenAt,
    }));
    return [...liveAsEntities, ...data.entities, ...loadedEntities];
  }, [liveEntities, dbExternalIds, data.entities, loadedEntities]);

  const handleLoadMore = async () => {
    if (!effectiveCursor || isLoadingMore) return;
    setIsLoadingMore(true);
    try {
      const result = await queryClient.fetchQuery(
        trpc.entities.list.queryOptions({
          category,
          limit: 30,
          cursor: effectiveCursor,
          search: filters.search || undefined,
        })
      );
      setLoadedEntities((prev) => [...prev, ...result.entities]);
      setNextCursor(result.hasMore ? result.nextCursor : null);
    } finally {
      setIsLoadingMore(false);
    }
  };

  return (
    <div className="space-y-4">
      {/* Filter bar */}
      <div className="flex items-center gap-3">
        <div className="relative max-w-sm flex-1">
          <Search className="absolute top-1/2 left-3 h-3.5 w-3.5 -translate-y-1/2 text-muted-foreground" />
          <Input
            className="pl-9"
            onChange={(e) => setSearchInput(e.target.value)}
            placeholder="Search entities..."
            value={searchInput}
          />
        </div>

        <Select
          onValueChange={(v) => {
            void setFilters({
              category: v as typeof filters.category,
            });
          }}
          value={filters.category}
        >
          <SelectTrigger className="w-[170px]">
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            {CATEGORY_OPTIONS.map((opt) => (
              <SelectItem key={opt.value} value={opt.value}>
                {opt.label}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>

        {status === "connected" && isDefaultView && (
          <div className="flex items-center gap-1.5 text-muted-foreground text-xs">
            <span className="flex h-2 w-2 animate-pulse rounded-full bg-emerald-500" />
            Live
          </div>
        )}
      </div>

      {/* Table */}
      {allEntities.length === 0 ? (
        <EmptyState />
      ) : (
        <div className="overflow-hidden rounded-lg border border-border/60">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead className="w-[120px]">Category</TableHead>
                <TableHead>Entity</TableHead>
                <TableHead className="w-[100px]">State</TableHead>
                <TableHead className="w-[80px] text-center">Seen</TableHead>
                <TableHead className="w-[120px] text-right">
                  Last active
                </TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {allEntities.map((entity) => (
                <EntityRow
                  entity={entity}
                  key={entity.externalId}
                />
              ))}
