"use client";

import type { EntityCategory } from "@repo/app-validation";
import { useTRPC } from "@repo/app-trpc/react";
import { Button } from "@repo/ui/components/ui/button";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@repo/ui/components/ui/table";
import { useSuspenseInfiniteQuery } from "@tanstack/react-query";
import { useMemo, useState } from "react";

interface EntityData {
  id: number;
  externalId: string;
  category: EntityCategory;
  key: string;
  value: string | null;
  state: string | null;
  url: string | null;
  confidence: number | null;
  occurrenceCount: number;
  lastSeenAt: string;
  extractedAt: string;
  createdAt: string;
}

export function EntitiesTable() {
  const trpc = useTRPC();

  const { data, hasNextPage, isFetchingNextPage, fetchNextPage } =
    useSuspenseInfiniteQuery(
      trpc.entities.list.infiniteQueryOptions(
        { limit: 30 },
        {
          getNextPageParam: (lastPage) => lastPage.nextCursor ?? undefined,
        }
      )
    );

  // -- Type assertions that prove the pattern works --

  // 1. clerkOrgId is accessible from first page and is string
  const clerkOrgId: string | undefined = data.pages[0]?.clerkOrgId;

  // 2. flatMap produces EntityData[]
  const dbEntities: EntityData[] = useMemo(
    () => data.pages.flatMap((page) => page.entities),
    [data.pages]
  );

  // 3. Live prepend pattern (mock - no realtime event yet)
  const [liveEntities] = useState<EntityData[]>([]);
  const dbIds = useMemo(
    () => new Set(dbEntities.map((e) => e.id)),
    [dbEntities]
  );

  const allEntities = useMemo(() => {
    const newLive = liveEntities.filter((e) => !dbIds.has(e.id));
    return [...newLive, ...dbEntities];
  }, [liveEntities, dbIds, dbEntities]);

  return (
    <div className="space-y-4">
      {/* Prove clerkOrgId is accessible */}
      {clerkOrgId && (
        <p className="text-xs text-muted-foreground">Org: {clerkOrgId}</p>
      )}

      <div className="overflow-hidden rounded-lg border border-border/60">
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>Category</TableHead>
              <TableHead>Key</TableHead>
              <TableHead>Value</TableHead>
              <TableHead className="text-right">Seen</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {allEntities.map((entity) => (
              <TableRow key={entity.id}>
                <TableCell>{entity.category}</TableCell>
                <TableCell>{entity.key}</TableCell>
                <TableCell>{entity.value ?? "-"}</TableCell>
                <TableCell className="text-right">
                  {entity.occurrenceCount}
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </div>

      {hasNextPage && (
        <div className="flex justify-center py-2">
          <Button
            disabled={isFetchingNextPage}
            onClick={() => void fetchNextPage()}
            variant="outline"
          >
            {isFetchingNextPage ? "Loading..." : "Load more"}
          </Button>
        </div>
      )}
    </div>
  );
}

