      string,
      (typeof PROVIDER_DISPLAY)[keyof typeof PROVIDER_DISPLAY] | undefined
    >
  )[event.source];

  return (
    <div className="flex items-start gap-3 border-border/60 border-b px-4 py-3 last:border-b-0">
