    entityEvent: z.object({
      entityExternalId: z.string(),
      clerkOrgId: z.string(),
      eventId: z.number(),
      eventExternalId: z.string(),
      observationType: z.string(),
      title: z.string(),
      source: z.string(),
      sourceType: z.string(),
      sourceId: z.string(),
      significanceScore: z.number().nullable(),
      occurredAt: z.string(),
      refLabel: z.string().nullable(),
    }),
  },
};

// Existing exports stay the same
